const normalize = (() => { try { return $('Normalize Input').first().json || {}; } catch { return {}; } })();
const root = (() => {
  try {
    const start = $('Start').first();
    if (start && start.json) return start.json;
  } catch {}
  if ($json && typeof $json === 'object' && Object.keys($json).length > 0) return $json;
  try {
    const current = $input.first();
    return (current && current.json) ? current.json : {};
  } catch {}
  return {};
})();
const formatEmptyCart = new Function('normalize', 'root', "\nconst toolInput = (root.tool_input && typeof root.tool_input === 'object') ? root.tool_input : root;\nconst chatId = String(normalize.chat_id || toolInput.chat_id || '');\nreturn {\n  chat_id: chatId,\n  message_type: 'button',\n  body_text: 'Your cart is empty right now.\\n\\nAdd a few items first and then tap checkout for the order summary.',\n  buttons: [\n    { id: 'start_shopping', title: 'Shop Items' },\n    { id: 'get_promos', title: 'Offers' },\n  ],\n  error: true,\n};\n");
return [{ json: formatEmptyCart(normalize, root) }];

const startRaw = $('Normalize Input').first().json || {};
const rawRows = $('Get Active Cart for Checkout').all().map((entry) => entry.json || {});
const promoRows = $input.all().map((entry) => entry.json || {}).filter((row) => row && row.promo_code);
const calculateFinalOrder = new Function('startRaw', 'rawRows', 'promoRows', "
const chatId = String(startRaw.chat_id || '');
const address = startRaw.checkout_address || null;

const normalizeUnit = (value) => {
  const map = { kg: 'kg', kilo: 'kg', kilos: 'kg', g: 'g', gm: 'g', gram: 'g', l: 'l', lt: 'l', ltr: 'l', litre: 'l', liters: 'l', ml: 'ml' };
  return map[String(value || '').toLowerCase().trim()] || String(value || '').toLowerCase().trim() || 'pcs';
};
const formatQty = (value) => Number.isInteger(Number(value)) ? String(Number(value)) : String(Number(Number(value).toFixed(3)));
const quantityLabel = (name, unit, qty) => {
  const lower = String(name || '').toLowerCase();
  const packMatch = lower.match(/(\d+(?:\.\d+)?)\s*(kg|g|ml|l)\b/i);
  if (/\bloose\b/.test(lower) && packMatch) return normalizeUnit(packMatch[2]);
  if (packMatch) return Number(qty) === 1 ? 'pack' : 'packs';
  return normalizeUnit(unit) || 'pcs';
};

const allItems = rawRows.filter((row) => row && row.cart_id);
if (allItems.length === 0) {
  return { confirmation_message: 'Your cart is empty.', chat_id: chatId, error: true };
}

if (!address || String(address).trim() === '' || String(address).toLowerCase() === 'undefined' || String(address).toLowerCase() === 'null') {
  return { needs_address: true, chat_id: chatId, final_order_total: 0, confirmation_message: 'Please provide your delivery address.' };
}

const firstItem = allItems[0];
const cartId = firstItem.cart_id;
let subtotal = 0;
const orderItems = allItems.map((row) => {
  const quantity = Number(row.quantity || 0);
  const unitPrice = Number(row.unit_price || 0);
  const lineTotal = quantity * unitPrice;
  subtotal += lineTotal;
  return {
    sku: row.sku,
    original_name: row.original_name,
    quantity,
    unit: row.unit || '',
    unit_price: unitPrice,
    line_total: lineTotal,
    display_quantity_unit: quantityLabel(row.original_name, row.unit, quantity),
  };
});

let totalDiscount = 0;
const appliedPromos = [];
if (promoRows.length > 0) {
  const promo = promoRows[0];
  const minCart = Number(promo.min_cart_value || 0);
  if (minCart === 0 || subtotal >= minCart) {
    let discount = 0;
    if (promo.discount_type === 'percentage') discount = Number((subtotal * Number(promo.discount_value || 0) / 100).toFixed(2));
    else if (promo.discount_type === 'flat') discount = Number(Math.min(Number(promo.discount_value || 0), subtotal).toFixed(2));
    if (discount > 0) {
      totalDiscount = discount;
      appliedPromos.push({
        code: promo.promo_code,
        discount,
        description: promo.description || (String(promo.discount_value || 0) + '% off'),
      });
    }
  }
}

const finalTotal = Number((subtotal - totalDiscount).toFixed(2));
const enablePricing = startRaw._enable_pricing !== false;
const itemLines = orderItems
  .map((entry) => {
    const base = '- ' + entry.original_name + ' x ' + formatQty(entry.quantity) + ' ' + entry.display_quantity_unit;
    return enablePricing ? base + ' = ₹' + entry.line_total.toFixed(2) : base;
  })
  .join('\n');
const discountLines = (enablePricing && appliedPromos.length > 0)
  ? '\nDiscounts:\n' + appliedPromos.map((promo) => '  ' + promo.code + ': -₹' + promo.discount.toFixed(2) + ' (' + promo.description + ')').join('\n')
  : '';
const pricingSummary = enablePricing
  ? '\nSubtotal: ₹' + subtotal.toFixed(2) + '\nYou save: ₹' + totalDiscount.toFixed(2) + '\nTotal Payable: ₹' + String(finalTotal)
  : '';
const billMsg =
  'Order Summary\n\n' +
  itemLines +
  discountLines +
  '\n\nDeliver to: ' + String(address) +
  pricingSummary;

return {
  order_id: 'ORD-' + String(chatId) + '-' + String(Date.now()),
  cart_id: cartId,
  chat_id: chatId,
  store_id: firstItem.store_id || 1,
  address,
  subtotal_before_discounts: subtotal,
  total_discount_applied: totalDiscount,
  final_order_total: finalTotal,
  applied_promos: appliedPromos,
  items_in_final_order: orderItems,
  confirmation_message: billMsg,
  error: false,
};
");
const pricingFlagRow = (() => {
  try { return $('Get Pricing Flag').first().json || {}; } catch { return {}; }
})();
startRaw._enable_pricing = pricingFlagRow.enable_pricing !== false;
return [{ json: calculateFinalOrder(startRaw, rawRows, promoRows) }];

const d = $json || {};
if (d.needs_address) return { json: d };
if (d.error) return { json: d };
const orderJson = JSON.stringify({
  order_id: d.order_id,
  cart_id: d.cart_id,
  chat_id: d.chat_id,
  store_id: d.store_id,
  address: d.address,
  subtotal_before_discounts: d.subtotal_before_discounts,
  total_discount_applied: d.total_discount_applied,
  final_order_total: d.final_order_total,
  applied_promos: d.applied_promos,
  items_in_final_order: d.items_in_final_order,
}).replace(/'/g, "''");
return { json: { ...d, order_details_json_safe: orderJson } };

const d = $('Prep Pending Order').first().json || {};
const returnBill = new Function('d', '$', "
if (d.needs_address) {
  const hasLastAddr = !!(d.last_address && d.last_address !== 'undefined' && d.last_address !== 'null');
  return {
    chat_id: d.chat_id,
    customer_ui_state: 'CHECKOUT_ADDRESS_REQUIRED',
    message_type: 'list',
    body_text: 'Delivery address needed\n\nSend the full address in one message. Example: 12 MG Road, Indiranagar, Bengaluru.',
    list_sections: [{
      title: 'Next steps',
      rows: hasLastAddr
        ? [
            { id: 'use_last_address', title: 'Use last address', description: String(d.last_address || '').slice(0, 60) },
            { id: 'add_address', title: 'Type new address', description: 'Send a fresh address in chat' },
            { id: 'view_cart', title: 'View cart', description: 'Review items before checkout' },
          ]
        : [
            { id: 'add_address', title: 'Type address', description: 'Send your address in chat' },
            { id: 'add_more', title: 'Add more items', description: 'Keep shopping before checkout' },
            { id: 'view_cart', title: 'View cart', description: 'Review items before checkout' },
          ],
    }],
  };
}

if (d.error) {
  return {
    chat_id: d.chat_id,
    customer_ui_state: 'CART_ACTIVE',
    message_type: 'button',
    body_text: String(d.confirmation_message || 'I could not prepare your order right now.'),
    buttons: [
      { id: 'view_cart', title: 'View Cart' },
      { id: 'start_shopping', title: 'Shop Items' },
    ],
    error: true,
  };
}

const readStore = () => {
  try { return $('Get Store Info').first().json || {}; } catch { return {}; }
};
const store = readStore();
const upiId = store.upi_id || '';
const storeName = store.store_name || 'Kirana Store';
const enablePricing = store.enable_pricing !== false;
let msg = String(d.confirmation_message || '').trim();
if (!enablePricing) {
  msg = msg.split('\n').filter((line) => {
    const l = line.trim();
    return !(l.match(/= ₹/) || l.startsWith('Subtotal:') || l.startsWith('You save:') || l.startsWith('Total Payable:') || l === 'Discounts:' || l.match(/^[A-Z0-9]+: -₹/));
  }).join('\n').trim();
}
if (upiId) {
  const upiLink = 'upi://pay?pa=' + encodeURIComponent(upiId) + '&pn=' + encodeURIComponent(storeName) + '&am=' + d.final_order_total + '&tn=' + d.order_id + '&cu=INR';
  msg += '\n\n💳 UPI payment\n' + upiLink;
}
msg += '\n\nConfirm to place this order. You can also change the address or add more items.';

return {
  chat_id: d.chat_id,
  customer_ui_state: 'CHECKOUT_REVIEW',
  message_type: 'list',
  body_text: msg.replace(/^Order Summary/i, 'Review your order'),
  list_sections: [{
    title: 'Checkout actions',
    rows: [
      { id: 'confirm_order', title: 'Confirm order', description: 'Place this order now' },
      { id: 'add_address', title: 'Change address', description: 'Update where this should be delivered' },
      { id: 'add_more', title: 'Add more items', description: 'Go back and keep shopping' },
    ],
  }],
  order_id: d.order_id,
  error: false,
};
");
return [{ json: returnBill(d, $) }];

